CREATE TABLE IF NOT EXISTS roles(id INT AUTO_INCREMENT PRIMARY KEY, role_key VARCHAR(50) UNIQUE NOT NULL, role_name VARCHAR(100) NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS permissions(id INT AUTO_INCREMENT PRIMARY KEY, permission_key VARCHAR(80) UNIQUE NOT NULL, permission_name VARCHAR(120) NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS role_permissions(role_id INT NOT NULL, permission_id INT NOT NULL, PRIMARY KEY(role_id,permission_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS users(id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(80) UNIQUE NOT NULL, name VARCHAR(120) NOT NULL, email VARCHAR(190) NULL, password_hash VARCHAR(255) NOT NULL, role_id INT NOT NULL, is_active TINYINT(1) DEFAULT 1, last_login_at DATETIME NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS settings(setting_key VARCHAR(100) PRIMARY KEY, setting_value TEXT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS units(id INT AUTO_INCREMENT PRIMARY KEY, unit_name VARCHAR(40) UNIQUE NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS stores(id INT AUTO_INCREMENT PRIMARY KEY, store_code VARCHAR(60) UNIQUE NOT NULL, store_name VARCHAR(160) NOT NULL, api_base_url VARCHAR(255) NOT NULL, api_token TEXT NULL, is_active TINYINT(1) DEFAULT 1, last_sync_at DATETIME NULL, notes TEXT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS raw_materials(id INT AUTO_INCREMENT PRIMARY KEY, code VARCHAR(60) UNIQUE NULL, name VARCHAR(160) NOT NULL, category VARCHAR(120) NULL, unit VARCHAR(40) NOT NULL, min_stock DECIMAL(18,4) DEFAULT 0, last_cost DECIMAL(18,2) DEFAULT 0, is_active TINYINT(1) DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS finished_products(id INT AUTO_INCREMENT PRIMARY KEY, code VARCHAR(80) NULL, sku VARCHAR(80) NULL, name VARCHAR(180) NOT NULL, category VARCHAR(120) NULL, unit VARCHAR(40) DEFAULT 'pcs', sale_price DECIMAL(18,2) DEFAULT 0, transfer_price DECIMAL(18,2) DEFAULT 0, image_path VARCHAR(255) NULL, source_store_id INT NULL, source_product_id VARCHAR(80) NULL, source_payload_json LONGTEXT NULL, is_active TINYINT(1) DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS finished_product_store_mappings(id INT AUTO_INCREMENT PRIMARY KEY, finished_product_id INT NOT NULL, store_id INT NOT NULL, store_product_id VARCHAR(80) NOT NULL, store_sku VARCHAR(100) NULL, store_product_name VARCHAR(180) NULL, store_price DECIMAL(18,2) DEFAULT 0, is_active TINYINT(1) DEFAULT 1, UNIQUE KEY uq_map(finished_product_id,store_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS product_import_logs(id BIGINT AUTO_INCREMENT PRIMARY KEY, store_id INT NULL, total_imported INT DEFAULT 0, message TEXT NULL, created_by INT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS purchase_headers(id BIGINT AUTO_INCREMENT PRIMARY KEY, purchase_no VARCHAR(60) UNIQUE NOT NULL, purchase_date DATE NOT NULL, supplier_name VARCHAR(160) NULL, status ENUM('draft','posted','cancelled') DEFAULT 'draft', total_amount DECIMAL(18,2) DEFAULT 0, notes TEXT NULL, created_by INT NULL, posted_at DATETIME NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS purchase_items(id BIGINT AUTO_INCREMENT PRIMARY KEY, purchase_id BIGINT NOT NULL, raw_material_id INT NOT NULL, qty DECIMAL(18,4) NOT NULL, unit VARCHAR(40) NOT NULL, unit_cost DECIMAL(18,2) NOT NULL, subtotal DECIMAL(18,2) NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS bom_headers(id BIGINT AUTO_INCREMENT PRIMARY KEY, bom_code VARCHAR(60) UNIQUE NOT NULL, finished_product_id INT NOT NULL, yield_qty DECIMAL(18,4) NOT NULL DEFAULT 1, notes TEXT NULL, is_active TINYINT(1) DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS bom_items(id BIGINT AUTO_INCREMENT PRIMARY KEY, bom_id BIGINT NOT NULL, raw_material_id INT NOT NULL, qty DECIMAL(18,4) NOT NULL, unit VARCHAR(40) NOT NULL, note VARCHAR(255) NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS production_headers(id BIGINT AUTO_INCREMENT PRIMARY KEY, production_no VARCHAR(60) UNIQUE NOT NULL, production_date DATE NOT NULL, bom_id BIGINT NOT NULL, finished_product_id INT NOT NULL, qty_produced DECIMAL(18,4) NOT NULL, status ENUM('draft','posted','cancelled') DEFAULT 'draft', notes TEXT NULL, created_by INT NULL, posted_at DATETIME NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS production_items(id BIGINT AUTO_INCREMENT PRIMARY KEY, production_id BIGINT NOT NULL, raw_material_id INT NOT NULL, qty_used DECIMAL(18,4) NOT NULL, unit VARCHAR(40) NOT NULL, unit_cost DECIMAL(18,2) DEFAULT 0) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS stock_ledger(id BIGINT AUTO_INCREMENT PRIMARY KEY, item_type ENUM('raw','finished') NOT NULL, item_id INT NOT NULL, trans_type VARCHAR(60) NOT NULL, ref_table VARCHAR(60) NOT NULL, ref_id BIGINT NOT NULL, qty_in DECIMAL(18,4) DEFAULT 0, qty_out DECIMAL(18,4) DEFAULT 0, unit_cost DECIMAL(18,2) NULL, note VARCHAR(255) NULL, created_by INT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX idx_item(item_type,item_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS kitchen_sales_headers(id BIGINT AUTO_INCREMENT PRIMARY KEY, sale_no VARCHAR(60) UNIQUE NOT NULL, sale_date DATE NOT NULL, store_id INT NULL, sale_type ENUM('direct','store_distribution') DEFAULT 'store_distribution', status ENUM('draft','posted','sent_to_store','received_by_store','failed_sync','cancelled') DEFAULT 'draft', total_amount DECIMAL(18,2) DEFAULT 0, notes TEXT NULL, created_by INT NULL, posted_at DATETIME NULL, synced_at DATETIME NULL, remote_response TEXT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS kitchen_sales_items(id BIGINT AUTO_INCREMENT PRIMARY KEY, sale_id BIGINT NOT NULL, finished_product_id INT NOT NULL, qty DECIMAL(18,4) NOT NULL, unit VARCHAR(40) NOT NULL, transfer_price DECIMAL(18,2) NOT NULL, subtotal DECIMAL(18,2) NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS activity_types(id INT AUTO_INCREMENT PRIMARY KEY, activity_name VARCHAR(160) NOT NULL, category VARCHAR(100) NULL, unit_name VARCHAR(40) DEFAULT 'kegiatan', point_weight DECIMAL(18,4) NOT NULL DEFAULT 1, is_active TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS employees(id INT AUTO_INCREMENT PRIMARY KEY, employee_name VARCHAR(160) NOT NULL, phone VARCHAR(60) NULL, is_active TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS employee_activities(id BIGINT AUTO_INCREMENT PRIMARY KEY, activity_date DATE NOT NULL, employee_id INT NOT NULL, activity_type_id INT NOT NULL, qty DECIMAL(18,4) NOT NULL DEFAULT 1, point_weight DECIMAL(18,4) NOT NULL DEFAULT 1, total_points DECIMAL(18,4) NOT NULL DEFAULT 1, notes TEXT NULL, created_by INT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS remuneration_periods(id BIGINT AUTO_INCREMENT PRIMARY KEY, period_name VARCHAR(120) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, total_fund DECIMAL(18,2) DEFAULT 0, status ENUM('draft','final') DEFAULT 'draft', created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS remuneration_items(id BIGINT AUTO_INCREMENT PRIMARY KEY, period_id BIGINT NOT NULL, employee_id INT NOT NULL, total_points DECIMAL(18,4) DEFAULT 0, point_percent DECIMAL(12,6) DEFAULT 0, amount DECIMAL(18,2) DEFAULT 0, UNIQUE KEY uq_rem(period_id,employee_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS api_tokens(id INT AUTO_INCREMENT PRIMARY KEY, token_name VARCHAR(120) NOT NULL, token_hash VARCHAR(255) NOT NULL, permissions_json TEXT NULL, is_active TINYINT(1) DEFAULT 1, last_used_at DATETIME NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS api_logs(id BIGINT AUTO_INCREMENT PRIMARY KEY, store_id INT NULL, endpoint VARCHAR(180) NULL, direction ENUM('in','out') DEFAULT 'out', status VARCHAR(40) NOT NULL, message TEXT NULL, payload_json LONGTEXT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS audit_logs(id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id INT NULL, action VARCHAR(120) NOT NULL, description TEXT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
